#include<cstdio>
using namespace std;

int main()
{
	int a[10001];
	int n,i,j,m,c,b,s=0;
	scanf("%d%d",&n,&m);
	for(int i=0;i<=n;i++)
	{
		a[i]=1;
	}
	for(i=1;i<=m;i++)
	{
		scanf("%d%d",&c,&b);
		for(j=c;j<=b;j++)
		{
			if(a[j]==0)
			{
				s+=0;
			}
			else
			{
				a[j]=0;
		        s++;
			}
		}
	}
    n=n+1-s;
	printf("%d",n);
	return 0;
}
